INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '35917d74-90d2-4fbd-8f1f-0b1788402525',
  '00000000-0000-0000-0000-000000000001',
  $escape$SwiftUI Concurrency — When to Use MainActor$escape$,
  $escape$When dealing with asynchronous operations in SwiftUI, `MainActor` ensures UI updates happen on the main thread. This is crucial for thread-safe, non-blocking UI updates. For example, consider a network fetch that updates a `@State` property. Wrap the network fetch in `Task.detached` to run it on a background thread, and ensure the UI update happens on the main thread using `Task.main.run`. This prevents potential deadlocks and ensures a responsive UI. Use `MainActor` when updating UI state from a background thread to avoid potential crashes.$escape$,
  $escape$import SwiftUI

struct ContentView: View {
    @State private var data = ""

    var body: some View {
        VStack {
            Text(data)
                .task {
                    // Run network fetch on background thread
                    Task.detached { await fetchData() }
                    // Update UI on main thread
                    await Task.main.run { data = "Fetched Data" }
                }
        }
    }

    func fetchData() async -> String {
        // Simulate network fetch
        await Task.sleep(nanoseconds: 1_000_000_000)
        return "Fetched Data"
    }
}$escape$,
  $escape$swift$escape$,
